import type * as DMMF from '@prisma/dmmf'

/**
 * Maps a Prisma DMMF field to its TypeScript type string, including list and
 * nullability modifiers. Only call this for scalar, enum, and unsupported
 * fields — relation (object) fields should be filtered out before reaching
 * here.
 */
export function mapPrismaTypeToTs(field: DMMF.Field): string {
  let base: string

  if (field.kind === 'unsupported') {
    base = 'unknown'
  } else if (field.kind === 'enum') {
    base = field.type
  } else {
    // scalar
    switch (field.type) {
      case 'String':
        base = 'string'
        break
      case 'Int':
      case 'Float':
      case 'Decimal':
        base = 'number'
        break
      case 'BigInt':
        base = 'bigint'
        break
      case 'Boolean':
        base = 'boolean'
        break
      case 'DateTime':
        base = 'Date'
        break
      case 'Json':
        base = 'unknown'
        break
      case 'Bytes':
        base = 'Uint8Array'
        break
      default:
        base = 'unknown'
    }
  }

  if (field.isList) {
    return `${base}[]`
  }
  if (!field.isRequired) {
    return `${base} | null`
  }
  return base
}

/** Returns true for fields that should appear in model interfaces and input types. */
function isDataField(field: DMMF.Field): boolean {
  return field.kind !== 'object'
}

/** Returns true for fields that are required in a CreateInput (required, no default, not ID). */
function isRequiredInCreate(field: DMMF.Field): boolean {
  if (!field.isRequired) return false
  if (field.hasDefaultValue) return false
  if (field.isId) return false
  if (field.isUpdatedAt) return false
  return true
}

/** Converts a model name to a URL-friendly plural path segment. */
function toUrlPath(modelName: string): string {
  return modelName.toLowerCase() + 's'
}

export function renderEnum(dmmfEnum: DMMF.DatamodelEnum): string {
  const values = dmmfEnum.values.map((v) => `'${v.name}'`).join(' | ')
  return `export type ${dmmfEnum.name} = ${values}\n`
}

export function renderModelInterface(model: DMMF.Model): string {
  const fields = model.fields.filter(isDataField)
  const lines = fields.map((f) => `  ${f.name}: ${mapPrismaTypeToTs(f)}`)
  return `export interface ${model.name} {\n${lines.join('\n')}\n}\n`
}

export function renderWhereUniqueInput(model: DMMF.Model): string {
  const uniqueFields = model.fields.filter((f) => isDataField(f) && (f.isId || f.isUnique))
  if (uniqueFields.length === 0) {
    // Fall back to all scalar fields so the type is never empty.
    const allScalar = model.fields.filter((f) => f.kind === 'scalar')
    if (allScalar.length === 0) {
      return `export type ${model.name}WhereUniqueInput = Record<string, never>\n`
    }
    const first = allScalar[0]!
    return `export type ${model.name}WhereUniqueInput = { ${first.name}: ${mapPrismaTypeToTs(first)} }\n`
  }
  const members = uniqueFields.map((f) => `{ ${f.name}: ${mapPrismaTypeToTs(f)} }`)
  return `export type ${model.name}WhereUniqueInput = ${members.join(' | ')}\n`
}

export function renderCreateInput(model: DMMF.Model): string {
  const fields = model.fields.filter(isDataField)
  const lines = fields.map((f) => {
    const required = isRequiredInCreate(f)
    const key = required ? f.name : `${f.name}?`
    return `  ${key}: ${mapPrismaTypeToTs(f)}`
  })
  return `export type ${model.name}CreateInput = {\n${lines.join('\n')}\n}\n`
}

export function renderUpdateInput(model: DMMF.Model): string {
  const fields = model.fields.filter(isDataField)
  // All fields are optional in an update — you only send what you want to change.
  const lines = fields.map((f) => `  ${f.name}?: ${mapPrismaTypeToTs(f)}`)
  return `export type ${model.name}UpdateInput = {\n${lines.join('\n')}\n}\n`
}

export function renderModelClient(model: DMMF.Model): string {
  const name = model.name
  const path = toUrlPath(name)

  return `export class ${name}Client {
  constructor(private readonly baseUrl: string) {}

  async findMany(params?: { skip?: number; take?: number }): Promise<${name}[]> {
    const url = new URL(\`\${this.baseUrl}/${path}\`)
    if (params?.skip !== undefined) url.searchParams.set('skip', String(params.skip))
    if (params?.take !== undefined) url.searchParams.set('take', String(params.take))
    const response = await fetch(url.toString())
    if (!response.ok) throw new Error(\`HTTP error \${response.status}\`)
    return response.json() as Promise<${name}[]>
  }

  async findUnique(where: ${name}WhereUniqueInput): Promise<${name} | null> {
    const key = Object.keys(where)[0]!
    const value = (where as Record<string, unknown>)[key]
    const response = await fetch(
      \`\${this.baseUrl}/${path}/\${encodeURIComponent(String(value))}?by=\${encodeURIComponent(key)}\`,
    )
    if (response.status === 404) return null
    if (!response.ok) throw new Error(\`HTTP error \${response.status}\`)
    return response.json() as Promise<${name}>
  }

  async create(data: ${name}CreateInput): Promise<${name}> {
    const response = await fetch(\`\${this.baseUrl}/${path}\`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(data),
    })
    if (!response.ok) throw new Error(\`HTTP error \${response.status}\`)
    return response.json() as Promise<${name}>
  }

  async update(where: ${name}WhereUniqueInput, data: ${name}UpdateInput): Promise<${name}> {
    const key = Object.keys(where)[0]!
    const value = (where as Record<string, unknown>)[key]
    const response = await fetch(
      \`\${this.baseUrl}/${path}/\${encodeURIComponent(String(value))}?by=\${encodeURIComponent(key)}\`,
      {
        method: 'PUT',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(data),
      },
    )
    if (!response.ok) throw new Error(\`HTTP error \${response.status}\`)
    return response.json() as Promise<${name}>
  }

  async delete(where: ${name}WhereUniqueInput): Promise<${name}> {
    const key = Object.keys(where)[0]!
    const value = (where as Record<string, unknown>)[key]
    const response = await fetch(
      \`\${this.baseUrl}/${path}/\${encodeURIComponent(String(value))}?by=\${encodeURIComponent(key)}\`,
      { method: 'DELETE' },
    )
    if (!response.ok) throw new Error(\`HTTP error \${response.status}\`)
    return response.json() as Promise<${name}>
  }
}
`
}

/**
 * Renders the top-level `RestClient` class that exposes one getter per model,
 * each returning a model-specific client instance.
 */
function renderRestClient(models: readonly DMMF.Model[]): string {
  const getters = models
    .map((m) => `  get ${toUrlPath(m.name)}(): ${m.name}Client {\n    return new ${m.name}Client(this.baseUrl)\n  }`)
    .join('\n\n')
  return `export class RestClient {
  constructor(private readonly baseUrl: string) {}

${getters}
}
`
}

/**
 * Produces the full `rest-client.ts` file content from a DMMF document.
 */
export function renderFile(dmmf: DMMF.Document): string {
  const { models, enums } = dmmf.datamodel
  const sections: string[] = []

  sections.push('// Auto-generated by @prisma/generator-rest-client. Do not edit manually.\n')

  if (enums.length > 0) {
    sections.push(enums.map(renderEnum).join('\n'))
  }

  sections.push(models.map(renderModelInterface).join('\n'))
  sections.push(models.map(renderWhereUniqueInput).join('\n'))
  sections.push(models.map(renderCreateInput).join('\n'))
  sections.push(models.map(renderUpdateInput).join('\n'))
  sections.push(models.map(renderModelClient).join('\n'))
  sections.push(renderRestClient(models))

  return sections.join('\n')
}

